mapper.sql:
where cc.tenant_id = #{tenantId}

    and cc.status = #{status}


    and cc.channel_id = #{channelId}


    and (
      cc.method_code like concat('%', #{keyword}, '%')
      or cc.terminal_type like concat('%', #{keyword}, '%')
      or cc.environment like concat('%', #{keyword}, '%')
      or m.method_name like concat('%', #{keyword}, '%')
      or c.channel_name like concat('%', #{keyword}, '%')
    )

mapper.delete:
delete from payment_channel_capability
where id = #{id}
  and tenant_id = #{tenantId}
